import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/launch-targets.DIrU2w_6.js";const s=JSON.parse(`{"title":"Launching the Game in VS Code","description":"Learn how to launch a Minecraft instance from Visual Studio Code.","frontmatter":{"title":"Launching the Game in VS Code","description":"Learn how to launch a Minecraft instance from Visual Studio Code.","authors":["dicedpixels"],"prev":{"text":"Opening a Project in VS Code","link":"./opening-a-project"},"next":{"text":"Generating Sources in VS Code","link":"./generating-sources"},"files":[]},"headers":[],"relativePath":"develop/getting-started/vscode/launching-the-game.md","filePath":"develop/getting-started/vscode/launching-the-game.md","lastUpdated":1759737061000}`);var c={name:`develop/getting-started/vscode/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Launching the Game in VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Launching the Game in VS Code”">​</a></h1><p>The Fabric toolchain integrates with Visual Studio Code to provide a convenient way to run a game instance to test and debug your mod.</p><h2 id="generating-launch-targets" tabindex="-1">Generating Launch Targets <a class="header-anchor" href="#generating-launch-targets" aria-label="Permalink to “Generating Launch Targets”">​</a></h2><p>To run the game with debugging support enabled, you will need to generate launch targets by running the <code>vscode</code> Gradle task.</p><p>This can be done from the Gradle View from within Visual Studio Code: open it and navigate to the <code>vscode</code> task in <strong>Tasks</strong> &gt; <strong><code>ide</code></strong>. Double click or use the <strong>Run Task</strong> button to execute the task.</p><p><img src="/assets/develop/getting-started/vscode/gradle-vscode.png" alt=" Task in Gradle View" loading="lazy"></p><p>Alternatively you can use the terminal directly: open a new terminal through <strong>Terminal</strong> &gt; <strong>New Terminal</strong> and run:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vscode</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vscode/terminal-vscode.png" alt=" Task in Terminal" loading="lazy"></p><h3 id="using-launch-targets" tabindex="-1">Using Launch Targets <a class="header-anchor" href="#using-launch-targets" aria-label="Permalink to “Using Launch Targets”">​</a></h3><p>Once launch targets are generated, you can use them by opening the <strong>Run and Debug</strong> view, selecting the desired target and pressing the <strong>Start Debugging</strong> button (<kbd>F5</kbd>).</p><p><img src="/assets/develop/getting-started/vscode/launch-targets.png" alt="Launch Targets" loading="lazy"></p>`,12)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};